<script>
    import { onMount } from "svelte";
    import { Link, navigate } from "svelte-routing";
    import HeroWebGL from "./HeroWebGL.svelte";
    import allContent from "../../data/content.json";

    const sortedContent = [...allContent]
        .sort((a, b) => new Date(b.date) - new Date(a.date));

    const categories = [...new Set(allContent.flatMap(item => item.tags))].sort((a, b) => a.localeCompare(b, "ko"));

    let selectedTag = "";
    let blogSection;
    let blogVisible = false;

    $: displayedContent = selectedTag
        ? sortedContent.filter(item => item.tags.includes(selectedTag))
        : sortedContent;

    function selectTag(tag) {
        selectedTag = selectedTag === tag ? "" : tag;
    }

    function scrollToBlog() {
        blogSection && blogSection.scrollIntoView({ behavior: "smooth" });
    }

    /* Intersection observer for blog fade-in */
    let articleEls = [];
    onMount(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add("visible");
                    }
                });
            },
            { threshold: 0.08, rootMargin: "0px 0px -40px 0px" }
        );

        // Observe blog section itself for header transition
        const blogObs = new IntersectionObserver(
            (entries) => {
                blogVisible = entries[0].isIntersecting;
            },
            { threshold: 0.05 }
        );

        if (blogSection) blogObs.observe(blogSection);

        // Slight delay to let DOM render
        setTimeout(() => {
            articleEls.forEach((el) => {
                if (el) observer.observe(el);
            });
        }, 100);

        return () => {
            observer.disconnect();
            blogObs.disconnect();
        };
    });

    function goToContent(id) {
        navigate(`/content/${id}`);
    }
</script>

<div class="home-redesign">
    <!-- ════════════════════════════════════════════
         SECTION 1: INTERACTIVE HERO
         ════════════════════════════════════════════ -->
    <HeroWebGL onScrollHint={scrollToBlog} />

    <!-- ════════════════════════════════════════════
         SECTION 2: MINIMAL BLOG
         ════════════════════════════════════════════ -->
    <section class="blog-section" bind:this={blogSection} id="blog-section">
        <div class="blog-inner">
            <!-- Blog Header -->
            <header class="blog-header fade-item" bind:this={articleEls[0]}>
                <h1 class="blog-title">Archive</h1>
                <p class="blog-subtitle">
                    수학, 자연 과학, 컴퓨터 과학에 대한 지식 기록
                </p>
            </header>

            <!-- Tag Filter -->
            <nav class="tag-filter fade-item" bind:this={articleEls[1]} aria-label="Category filter">
                <button
                    class="tag-btn"
                    class:active={selectedTag === ""}
                    on:click={() => selectTag("")}
                >
                    전체
                </button>
                {#each categories as tag}
                    <button
                        class="tag-btn"
                        class:active={selectedTag === tag}
                        on:click={() => selectTag(tag)}
                    >
                        {tag}
                    </button>
                {/each}
            </nav>

            <!-- Content List -->
            <div class="blog-list">
                {#each displayedContent as item, i}
                    <article
                        class="blog-item fade-item"
                        bind:this={articleEls[i + 2]}
                        on:click={() => goToContent(item.id)}
                        on:keydown={(e) => e.key === "Enter" && goToContent(item.id)}
                        tabindex="0"
                        role="link"
                    >
                        <div class="blog-item-header">
                            <time class="blog-date">{item.date}</time>
                            <div class="blog-tags">
                                {#each item.tags.slice(0, 3) as tag}
                                    <span class="blog-tag">{tag}</span>
                                {/each}
                            </div>
                        </div>
                        <h2 class="blog-item-title">{item.title}</h2>
                        <p class="blog-item-desc">{item.description}</p>
                        <span class="blog-item-arrow">→</span>
                    </article>
                {/each}

                {#if displayedContent.length === 0}
                    <p class="empty-state">해당 카테고리에 콘텐츠가 없습니다.</p>
                {/if}
            </div>

            <!-- Quick Navigation -->
            <nav class="quick-nav fade-item" bind:this={articleEls[displayedContent.length + 2]}>
                <h3 class="quick-nav-title">탐색</h3>
                <div class="quick-nav-links">
                    <Link to="/mathpage" class="quick-link">수학</Link>
                    <Link to="/sciencepage" class="quick-link">자연 과학</Link>
                    <Link to="/cspage" class="quick-link">컴퓨터 과학</Link>
                </div>
            </nav>
        </div>
    </section>
</div>

