<script>
  import { onMount } from 'svelte';
  import Swiper from 'swiper';
  import 'swiper/swiper-bundle.css';
  import { navigate } from "svelte-routing";

  export let title;
  export let contentItems = [];
  export let subtitle = "";

  let swiperContainer;

  onMount(() => {
    const swiper = new Swiper(swiperContainer, {
      loop: true,
      slidesPerView: 3,
      spaceBetween: 30,
      autoHeight: false,
      breakpoints: {
        0: {
          slidesPerView: 1.08,
          spaceBetween: 16
        },
        700: {
          slidesPerView: 2.1,
          spaceBetween: 20
        },
        1100: {
          slidesPerView: 3,
          spaceBetween: 30
        }
      },
      pagination: {
        el: '.swiper-pagination',
        clickable: true,
      },
    });

    return () => swiper.destroy(true, true);
  });

  function goToContentDetail(id) {
    navigate(`/content/${id}`);
  }

  function handleKeydown(event, id) {
    if (event.key === 'Enter' || event.key === ' ') {
      goToContentDetail(id);
    }
  }
</script>

<div class="carousel-section">
  <div class="section-heading">
    <div>
      <span class="section-kicker">Collection</span>
      <h2>{title}</h2>
    </div>
    {#if subtitle}
      <p>{subtitle}</p>
    {/if}
  </div>
  <div class="swiper-container" bind:this={swiperContainer}>
    <div class="swiper-wrapper">
      {#each contentItems as item (item.id)}
        <div
          class="swiper-slide slide-panel"
          on:click={() => goToContentDetail(item.id)}
          on:keydown={(e) => handleKeydown(e, item.id)}
          style="cursor: pointer;"
          tabindex="0"
          role="button"
        >
          <div class="slide-top">
            <span class="slide-date">{item.date}</span>
            <span class="slide-arrow">↗</span>
          </div>
          <h3>{item.title}</h3>
          <p class="description">{item.description}</p>
          <p class="tags">#{item.tags.length}</p>
        </div>
      {/each}
      {#if contentItems.length === 0}
        <div class="swiper-slide">콘텐츠 없음</div>
      {/if}
    </div>
    <div class="swiper-pagination"></div>
  </div>
</div>

